# Module-level state (shared across the module)
instance_count: int = 0

class Calculator:
    def __init__(self):
        global instance_count
        instance_count += 1
        self._value: int = 0

    def get_value(self) -> int:
        return self._value

    def set_value(self, v: int) -> None:
        self._value = v

    def add(self, a: int, b: int) -> int:
        return a + b

    def multiply(self, a: int, b: int) -> int:
        return a * b

